# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import json
import pymysql

def lambda_handler(event, context):
    conn = pymysql.connect(host='your_rds_endpoint',
                            user='your_username',
                            password='your_password',
                            db='your_database')

    cursor = conn.cursor()

    search_params = json.loads(event['body'])
    search_query = ""

    if 'product_name' in search_params:
        product_name = search_params['product_name']
        search_query += f"WHERE product_name LIKE '%{product_name}%'"

    if 'category' in search_params:
        category = search_params['category']
        search_query += f"WHERE category = '{category}'"

    if not search_query:
        cursor.execute("SELECT * FROM products")
    else:
        search_query += " FROM products"
        cursor.execute(search_query)

    results = cursor.fetchall()

    response = {
        'statusCode': 200,
        'body': json.dumps(results)
    }

    conn.close()
    return response